/** 
*   @brief The function sets the priority grouping field using the required unlock sequence.
*   @param[in]  PriorityGroup    The parameter PriorityGroup is assigned to the field IP_IP_SCB->AIRCR [10:8] PRIGROUP field 
*   @arg        
*   @arg        
*
* 
*   @return     void       This function return void value.
*/
/*================================================================================================*/
void NVIC_SetPriorityGrouping(uint32 PriorityGroup)
{
    /* Set the PRIGROUP[10:8] bits according to NVIC_PriorityGroup value */
    SCB->AIRCR = (SCB->AIRCR & (~0x700UL)) | PriorityGroup;
}

/*================================================================================================*/
/** 
* @brief The function enables a device-specific interrupt in the NVIC interrupt controller.
* @param[in]  IRQn      Device specific interrupt number
* @arg        
* @arg
* 
* @return     void       This function return void value.
*/
/*================================================================================================*/ 
void NVIC_EnableIRQ(uint8 IRQn)
{
    NVIC->ISER[(uint32)(IRQn) >> 5U] = (uint32)(1UL << ((uint32)(IRQn) & (uint32)0x1FU));
}

/*================================================================================================*/
/** 
* @brief The function disables a device-specific interrupt in the NVIC interrupt controller
* @param[in]  IRQn      Device specific interrupt number
* @arg        
* @arg
* 
* @return     void       This function return void value.
*/
/*================================================================================================*/  
void NVIC_DisableIRQ(uint8 IRQn)
{
    NVIC->ICER[(uint32)(IRQn) >> 5U] = (uint32)(1UL << ((uint32)(IRQn) & (uint32)0x1FU));
}
 
 
/*================================================================================================*/
/** 
* @brief The function sets the priority of an interrupt.
* @param[in]  IRQn      Device specific interrupt number
* @param[in]  p_priority_u8  Priority  Priority to set
* @arg        
* @arg
* 
* @return     void       This function return void value.
*/
/*================================================================================================*/  
void NVIC_SetPriority(uint8 IRQn, uint8 p_priority_u8)
{
    uint8 p_shift_u8 = (uint8) (8U - FEATURE_NVIC_PRIO_BITS);
    NVIC->IP[(uint32)(IRQn)] = (uint8)(((((uint32)p_priority_u8) << p_shift_u8)) & 0xFFUL);
}

